import{_ as t,o as e,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"📈 市場行情與趨勢看板指南","description":"","frontmatter":{},"headers":[],"relativePath":"Market-Analytics.md","filePath":"Market-Analytics.md"}'),l={name:"Market-Analytics.md"};function i(n,a,s,c,d,_){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="📈-市場行情與趨勢看板指南" tabindex="-1">📈 市場行情與趨勢看板指南 <a class="header-anchor" href="#📈-市場行情與趨勢看板指南" aria-label="Permalink to &quot;📈 市場行情與趨勢看板指南&quot;">​</a></h1><p>為了引導伺服器的物價走勢，防止價格壟斷或漫天要價，系統內建了交易成交價格統計與行情趨勢看板。</p><hr><h2 id="_1-📊-系統交易數據記錄" tabindex="-1">1. 📊 系統交易數據記錄 <a class="header-anchor" href="#_1-📊-系統交易數據記錄" aria-label="Permalink to &quot;1. 📊 系統交易數據記錄&quot;">​</a></h2><p>當玩家在伺服器中透過任何「箱子商店」完成交易時，系統會自動記錄該筆成交資訊：</p><ul><li>成交商品名稱與物品 ID</li><li>成交單價</li><li>成交數量</li><li>交易時間</li></ul><hr><h2 id="_2-📈-行情趨勢選單-market" tabindex="-1">2. 📈 行情趨勢選單 <code>/market</code> <a class="header-anchor" href="#_2-📈-行情趨勢選單-market" aria-label="Permalink to &quot;2. 📈 行情趨勢選單 `/market`&quot;">​</a></h2><p>玩家可以在遊戲內輸入 <strong><code>/market</code></strong> 開啟伺服器行情趨勢選單：</p><ul><li><strong>今日平均成交價</strong>：系統會自動計算過去 24 小時內，全服玩家箱子商店中該商品所有真實成交單價的平均值。</li><li><strong>7 日物價走勢百分比</strong>：系統會將今日均價與 7 天前的均價進行對比，並標示漲跌幅度： <ul><li><strong>▲ 綠色三角形</strong>：代表物價相比 7 天前上漲，並標示漲幅百分比（如 <code>▲ +12%</code>）。</li><li><strong>▼ 紅色三角形</strong>：代表物價相比 7 天前下跌，並標示跌幅百分比（如 <code>▼ -8%</code>）。</li><li><strong>● 灰色圓點 / 持平</strong>：代表物價在過去 7 天內保持穩定，無明顯物價波動。</li></ul></li></ul><p>這套機制為新加入伺服器的玩家與準備開店定價的賣家們，提供了一個可靠的物價參考指標。</p>',11)])])}const m=t(l,[["render",i]]);export{p as __pageData,m as default};
